window.__QUIZ_DATA__=[{"id":"objective>Geography>2004>1","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scale of the map is representative fraction is","images":["data:image/png;base64,"],"options":{"A":"1:50,000","B":"1:100,000","C":"1:150,000","D":"1:250,000"},"answer":"B","explanation":"Linear scale to Representative fraction.  1cm to rep 1km  =1cm to (1km \u22c6 100,000)= 1cm to 100,000cm  \u2234 1/100000=1:100,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>2","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The bearing of ududu from achala is approximately","images":["data:image/png;base64,"],"options":{"A":"25\u2218","B":"115\u2218","C":"155\u2218","D":"205\u2218"},"answer":"D","explanation":"From the map; The bearing of Ududu from Achala is approximately \"205\u2218 because it is located around the south-west to Ududu.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>3","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The features marked X is a good example of a","images":["data:image/png;base64,"],"options":{"A":"Cliff","B":"saddle","C":"knoll","D":"scrap"},"answer":"B","explanation":"From the map: The feature X is a good example of saddle which is also known as Col. It is a stretch of lowland which separates highland areas.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>4","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The approximate distance from fakat to aduba 'as the crow flies' is","images":["data:image/png;base64,"],"options":{"A":"5KM","B":"10KM","C":"12KM","D":"15KM"},"answer":"D","explanation":"From the map, Map distance=15cm                      Ground distance=?                           Map scale=1:100,000                       Ground distance = 15cm \u22c6 100,000/ 100,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>5","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Bako is a good example of a","images":["data:image/png;base64,"],"options":{"A":"confluence town","B":"linear settlement","C":"mining town","D":"conurbation"},"answer":"A","explanation":"From the map, Bako is a confluence town in which is located around the meeting point of two rivers. For example; Bako in Ududu district which is a confluence town.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>6","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The contour interval on the map is","images":["data:image/png;base64,"],"options":{"A":"50m","B":"100m","C":"150m","D":"180m"},"answer":"B","explanation":"From the map, The contour interval is 100m. For example from the map the contours in metres are 200,400 and 600.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>7","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The feature marked A-D can best described as","images":["data:image/png;base64,"],"options":{"A":"a knoll","B":"an iselberg","C":"a plateau","D":"a ridge"},"answer":"D","explanation":"From the map,The feature marked A-D is a ridge. A ridge is a strip of highland which is elongage and narrow. The contours run almost parallel to each other.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>8","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following settlement is not visible from boko?","images":["data:image/png;base64,"],"options":{"A":"Aduba","B":"goda","C":"Hamas","D":"Odima"},"answer":"D","explanation":"From the map, Odima is not visible from Bako because it is far away from the confluence town but the other areas are visible to Bako because they are nearer.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>9","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is not likely to be an occupation in the area","images":["data:image/png;base64,"],"options":{"A":"Farming","B":"lumbering","C":"fishing","D":"mining"},"answer":"D","explanation":"Mining is not likely to be an occupation in the area because the area is filled with rivers, scattered cultivation, forest, savanna, and so on.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>10","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The area covered by the map is approximately","images":["data:image/png;base64,"],"options":{"A":"200Km2","B":"205KM2","C":"250KM2","D":"270KM2"},"answer":"B","explanation":"From the map,   Area = Length \u22c6 Breadth  Area = 14.5km \u22c6 14.1km  Area covered = 204.45  By map is approximately 205km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>11","subject":"Geography","year":"2004","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Export crop production of Nigeria, 1990(Metric tonnes) (total output was 400,000 metric tonnes)      What is the total output of cocoa?","images":["data:image/png;base64,"],"options":{"A":"100,000","B":"111,111","C":"122,111","D":"133,111"},"answer":"B","explanation":"Total output of cocoa= 100/360 \u22c6 400,000.                                     = 111,111  \u2234 The total output of cocoa in figure 1 is 111,111.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>12","subject":"Geography","year":"2004","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Export crop production of Nigeria, 1990(Metric tonnes) (total output was 400,000 metric tonnes)    The percentage production of palm oil is ?","images":["data:image/png;base64,"],"options":{"A":"20.60","B":"18.86","C":"16.67","D":"14.86"},"answer":"C","explanation":"Percentage production of = 60/360 \u22c6 100%                                             =16.67%  \u2234The percentage of palm oil in Figure 1 is 16.67%","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>13","subject":"Geography","year":"2004","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Export crop production of Nigeria, 1990(Metric tonnes) (total output was 400,000 metric tonnes)    The total output of cashew and cotton is","images":["data:image/png;base64,"],"options":{"A":"88.889","B":"99,999","C":"100,000","D":"110,000"},"answer":"A","explanation":"Cashew= 50/360 \u22c6 400,000               = 55,555.5  Cotton = 30/360  \u22c6 400,000              = 33,333.3  Total output of cashew and cotton              =55,555.5 + 33,333.3              =88,888.8              \u2248 88,889.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>14","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"If the time is 10.00 am in belfast (longitude 60\u2218W), th time at leningrad(longitude 30\u2218) will be","images":[],"options":{"A":"4.00 am","B":"12.00 noon","C":"4.00 pm.","D":"6.00 pm"},"answer":"B","explanation":"Longitude difference = 60 0W - 30 0E =30 0  15 0\u22b8 1 hour = 15x = 30  30 0\u22b8 x hour = x    = 2 hours  \u2234 The 30 0 gives us 2 hours  10.00am + 2 hours = 12.00 noon  \u2234The time at Leningrad is 12.00 noon","marks":"1","difficulty":"3"},{"id":"objective>Geography>2004>15","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following planets has twelve satellites?","images":[],"options":{"A":"Neptune","B":"Mars","C":"Jupiter","D":"Uranus"},"answer":"C","explanation":"Jupiter has twelve satellites. It is the largest planet in the solar system its distance from the sun is 772,800,000 km.  It takes jupiter about 11.9 years to complete its orbit around the sun.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2004>16","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is known as the lad of midnight sun","images":[],"options":{"A":"Tropic of cancer","B":"Artic circle","C":"Antarctic circle","D":"tropic of capricorn"},"answer":"C","explanation":"The region from Arctic circle to the north pole as this time is called \"the land of the midnight sun\". It usually happen in the Northern hemisphere, during summer around June 21.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2004>17","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The part of the earth crust that is covered by oceans and sea is called","images":[],"options":{"A":"biosphere","B":"Hydrosphere","C":"ionosphere","D":"stratosphere"},"answer":"B","explanation":"Hydrosphere is the liquid portion of the earth. It covers about 70% of the earth's crust. It includes all forms of fresh water like lakes,rivers,water vapour.  It also includes ocean water which is salty.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2004>18","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The process which causes exposed rock surface to break and crumble us  best described ?","images":[],"options":{"A":"Denudation","B":"Waethering","C":"Transportation","D":"folding."},"answer":"B","explanation":"Weathering is defined as the gradual breaking down or disintegration of rocks by either physical(mechanical) or chemical process. It also causes exposed rock surfaces to break and crumble.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>19","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Marble is a metamorphic rock formed form","images":[],"options":{"A":"Denudation","B":"waethering","C":"Granite","D":"coal"},"answer":"B","explanation":"Metamorphic rocks are formed from pre-existing igneous or sedimentary rocks which have been changed as a result of great heat and pressure. One example of metamorphic rocks is marble. Marble.Marble is a metamorphic rock formed from Limestone.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>20","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is not true of the relationship between the sun and the earth?","images":[],"options":{"A":"Earth is held by sun's gravitational force","B":"Sun supplies heat and light energy to the earth","C":"sun revolves round the earth","D":"The distace from the earth to the sun is 150 Million kilometer"},"answer":"C","explanation":"The sun does not revolve round the earth but the earth revolve round the sun for 365 days which is approximately(One year). The sun supplies heat and light energy to the earth and the earth rotates round its axis in a day.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2004>21","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Earth movement generate tensional forces that","images":[],"options":{"A":"Pull the crust apart","B":"act toward one another","C":"wrinkle the crust","D":"pull the crust towards one another"},"answer":"A","explanation":"The earth's movements generate tensional forces that pull the crust apart due to gravitational forces that pull the crust apart from the earth's surface.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>22","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following is not an example of a fold mountain ?","images":[],"options":{"A":"Andes","B":"kilimanaro","C":"Rokies","D":"Himalayas"},"answer":"B","explanation":"Fold mountains are formed by large scale horizontal earth movement as a result of stress and compressional forces which cause expansion or contraction of some parts of the earth. Examples of some parts of the earth.Examples of fold mountains include Himalayas, Rockies, Andes,Alps and Atlas mountains. Kilimanjaro is an example of Volcanic mountains.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>23","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Down floded layer of chalk or limestone sandwiched between impermeable rock layers and containing trapped water is reffered to as","images":[],"options":{"A":"River basin","B":"oasis","C":"artesian basin","D":"watershed"},"answer":"C","explanation":"Artesian basin consists of a layer of permeable rock lying between two layers of impermeable rocks such that the whole forms a shallow syncline with one or both ends of the permeable rock layer exposed to the surface.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2004>24","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The seasonal variation in the volume of water in a river is known as the","images":[],"options":{"A":"regime","B":"drainage","C":"pattern","D":"waterdivide"},"answer":"A","explanation":"River regime refers to the seasonal changes in the volume of water in a river in a year. It could be single regime where there is one period of high volume and one period of low volume. It is also the seasonal variation in the volume of water in a river.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>25","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is not a process of chemical weathering?","images":[],"options":{"A":"Hydrolysis","B":"Oxidation","C":"carbonation","D":"frost action"},"answer":"D","explanation":"Chemical weakening is the gradual disintegration of rocks due to their exposure to air and water. It include solution, oxidation, carbonation, hydration, hydrolysis, which are its processes. Frost action is a process of physical or mechanical weathering.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>26","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The plains formed when the slopes of mountained are worn back in arid and semi-arid region by mechanical weathering is called?","images":[],"options":{"A":"Pediplans","B":"deflation plains","C":"alluvial plains","D":"outwash plains"},"answer":"A","explanation":"Pediplans are formed when wind blows and reduces a highland to a flat or level but a gentle land is called a pediplain. It is also a plain formed when the slopes of mountains are worn back in arid and semi-arid regions by mechanical weathering.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>27","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"They are crescentic or moon-shaped and occur individually or groups''. The above description refers to","images":[],"options":{"A":"yardangs","B":"Barchans","C":"seifs","D":"Rock pedestals"},"answer":"B","explanation":"A barchan is a cresentic or moon shaped structure. They may occur in groups or singly. A barchan has a convex shape on windward side and a concave shape on the leeward side with horns of 15-30m long. It is formed by wind deposition in deserts.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>28","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Lines oining places of equal sunshine duration on maps are known as","images":[],"options":{"A":"isohyet","B":"isoneph","C":"isobar","D":"isohel"},"answer":"D","explanation":"Isohel are lines joining places of equal sunshine duration on maps. These lines are lines that helps join the places of equal sunshine in the map during any duration.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>29","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A well will always contain  water if it is dug","images":[],"options":{"A":"above the water table","B":"below the water table","C":"to reach sand bearing water","D":"below the earth basin"},"answer":"B","explanation":"A well is formed when a hole is sunk into the ground far below the water table. Water then seeps out of the rocks into the hole to form a well.When a well is sunk far below the water table, it always contain water below the water table.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>30","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following is not a factor affecting the movement of ocean currents?","images":[],"options":{"A":"The planetay winds","B":"Difference in temperature","C":"shape of the landmass","D":"Difference in the rate of evapouration"},"answer":"D","explanation":"Factors affecting movement of ocean currents are; the planetary winds, differences in temperature, shape of the landmass, salinity,rotation of the earth. Differences in the rate of evaporation is not a factor affecting movement of ocean currents.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>31","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"When there is a  large difference in the reading of the dry ad wet bulb thermometer, its show that relative humidity is","images":[],"options":{"A":"Low","B":"moderate","C":"100%","D":"0%"},"answer":"A","explanation":"The wet bulb always shows a lower reading than the dry bulb. The difference in the two readings, if high, indicates low humidity and if low, indicates high humidity. Therefore, when there is a large difference, relative humidity is low.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>32","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The peeling off of the surface years layers of rounded boulders during mechanical weathering is called ?","images":[],"options":{"A":"Frost action","B":"exfoliation","C":"solifluction","D":"rock fragmentation"},"answer":"B","explanation":"Exfoliation is the process involved in the peeling off of the rock surface. It is also the peeling off of the rock surface layers of the rounded boulders during mechanical weathering. Exfoliation is an agents of temperature changes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>33","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is associated with wind deflation in arid regions?","images":[],"options":{"A":"Rock pedestals","B":"oasis","C":"barchan","D":"yardangs"},"answer":"B","explanation":"Oasis are formed when water seeps out as a result of wind deflation, large depressions or hollows are produced by the scooping away of loose sandy materials by wind, sometimes below the water table. It is also known as swamps.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>34","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Laterization is a soil-formation process prominent in","images":[],"options":{"A":"Hot humid tropics","B":"cool tenperate zones","C":"warm temperate zones","D":"temperate grassland"},"answer":"A","explanation":"Laterization is a soil-forming process prominent in hot humid tropics. Laterization is the process whereby soils are heavily leached of bases and silica leaving behind concentration of alluminium and Iron minerals.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>35","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"''it is ade up of a great  variety of evergreen trees, eith a distict layer arrangement'', refers to the","images":[],"options":{"A":"equatorial forest","B":"tropical grassland","C":"temperature grassland","D":"coniferous forces"},"answer":"A","explanation":"Equatorial forest are found in the western part of West Africa.They are made up of a great variety of evergreen trees, with a distinct layer arrangements which makes it looks beautiful.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>36","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Organic component of the soil include, all the following except","images":[],"options":{"A":"humus","B":"animal remains","C":"micro-organism","D":"rock pedestals"},"answer":"D","explanation":"Organic components are the remains of the decomposition of plants and animal. They include: humus, animal remains, micro organisms. Rock pedestral is a feature of wind erosion in the desert which has a flat shape and irregular surface.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>37","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following does not determine the available human resources in a country?","images":[],"options":{"A":"Births","B":"Deaths","C":"Emigration","D":"Evolution"},"answer":"D","explanation":"Evolution does not determine the available human resources in a country. Births,deaths,emigration,immigration,migration are factors that affect human resources in a country under the world population census.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>38","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"If the land area of a place is 900,000 square kilometres , and its total population is 120,000,000. what is the population density of the area?","images":[],"options":{"A":"144 person per square kilometre","B":"133 persons per square kilometre","C":"122 persons per square kilometre","D":"111 person per square kilometre"},"answer":"B","explanation":"Population density = Total population/ land Area                                                                   =120000000/900000                                      =133 persons per square kilometre  \u2234Population density of the aea is 133 persons per square kilometre.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2004>39","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The relative advantage of road transport over other modes transport is its","images":[],"options":{"A":"Flexibilty","B":"fastness","C":"safety","D":"comfortability"},"answer":"A","explanation":"Road transport involves the use of motor cars, buses, motor cycles, lorries and trucks to move people and goods from one place to another. It is the most common means of transportation. It is flexible and makes goods available where they are scarce.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>40","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Iron and steel industry is most likely to be located near the","images":[],"options":{"A":"raw material","B":"market","C":"power supply","D":"labour supply"},"answer":"A","explanation":"Iron and steel industry is most likely to be located near the raw materials because they are heavy and bulky which deals with heavy industries. It is important to be located near raw material to reduce cost of transportation.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>41","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"When two or more towns grow to join each or one another and still retain their the identities they form a","images":[],"options":{"A":"metropolis","B":"conurbation","C":"domitory town","D":"satelite town"},"answer":"B","explanation":"Conurbation is  a type of urban settlement which is made up of several towns joined together but each town still maintains its identity. It is densely populated with heterogenous people who do not know one another very well.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>42","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The import of most developing countries consist mainly of","images":[],"options":{"A":"crafts","B":"mineral resource","C":"manufactured goods","D":"agricutlture raw materials"},"answer":"C","explanation":"Developing countries like China,Japan,Canada,France,Belgium,Nigeria,England and so on imports goods which are manufactured goods like bags,pen,foodstuffs and so on. which attracts foreign income to the country at large.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>43","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of th following ports has the best natural harbour in West Africa","images":[],"options":{"A":"Lagos","B":"freetown","C":"Banjul","D":"takoradi"},"answer":"B","explanation":"Freetown is the capital of sierra leone which is one of the country of West Africa. It is the best natural harbour in West Africa due to its location near the ocean.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>44","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The high population density in the coastal areas of west Africa can best be explained by","images":[],"options":{"A":"is rugged belief","B":"the concentration of industries in the area","C":"Presence of sandy soils","D":"its inaccessibilty"},"answer":"B","explanation":"The high population density in the coastal areas of West Africa can be explained by the concentration of industries in the area and other activities which can promote or increase the population density.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>45","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The differential heating pf the land and sea result in","images":[],"options":{"A":"fog","B":"precipitation","C":"land and sea breeze","D":"upwelling  of water"},"answer":"C","explanation":"Land and sea breezes are local winds which blow alternately between land and sea on a daily basics. The breeze exchange between the land and the sea is attributed to differential heating of land and sea.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>46","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Wind  generally blow from an area of","images":[],"options":{"A":"high pressure to area of low pressure","B":"low pressure to area of high pressure","C":"high rainfall to area of low rainfall","D":"low rainfall to a area of high rainfall"},"answer":"A","explanation":"It is an established fact that wind blows from areas of high pressure to areas of low pressure and this forms the basis of wind movement. The wind blow from the sub-tropical high pressure belts to the equatorial low pressure belts.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>47","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"the trees are tall and evergreen, leafs are small, thick leathery and needle shaped . this is a description of the","images":[],"options":{"A":"equatorial forest","B":"coniferous forest","C":"mediterranean woodland","D":"savanna woodland"},"answer":"B","explanation":"Coniferous forest is found only in the northern hemisphere,especially in North America,former U.S.S.R,Europe. The trees are conical in shape, almost all the conifers are evergreen, trees are pure stand and homogenous.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>48","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Water erosion in arid regions produces","images":[],"options":{"A":"yardang","B":"canyons","C":"inserbergs","D":"deflation hollows"},"answer":"D","explanation":"Deflation hollows are formed by wind deflation. It is a desert landform with varying depths. It is very extensive and can form oasis in deserts. It is produced by water erosion in arid regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>49","subject":"Geography","year":"2004","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"marekets gardening referes to the growing of vegetables","images":[],"options":{"A":"near a swampy area","B":"in a small village","C":"in a high land area","D":"around  large towns."},"answer":"D","explanation":"Market gardening refers to the growing of vegetables,fruits and flowers around large towns in order to bring or provide foreign exchange betweeen the towns and other towns around the area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2004>50","subject":"Geography","year":"2004","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The climate of equitorila regions of west Africa is charateristics by","images":[],"options":{"A":"summer, autumn, winter and spring","B":"short dry season and short wet season","C":"two rainy season with a sort dry seasons","D":"summer and winter"},"answer":"D","explanation":"The climate of the equatorial regions of West Africa is characterized by summer and winter.In  the equatorial regions the summer season comes first while the winter follows. The summer is when there is lot of sunshine while the winter is when there is little of sunshine.","marks":"1","difficulty":"2"}];